DROP TABLE IF EXISTS `item_variants`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `item_variants` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `item_id` bigint unsigned NOT NULL,
  `item_color_id` bigint unsigned DEFAULT NULL,
  `item_size_id` bigint unsigned DEFAULT NULL,
  `images` json DEFAULT NULL,
  `item_packaging_type_id` bigint unsigned DEFAULT NULL,
  `sku` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `barcode` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `status` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'active',
  `owner_id` bigint unsigned DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `item_variants_sku_unique` (`sku`),
  KEY `item_variants_item_id_foreign` (`item_id`),
  KEY `item_variants_item_color_id_foreign` (`item_color_id`),
  KEY `item_variants_item_size_id_foreign` (`item_size_id`),
  KEY `item_variants_item_packaging_type_id_foreign` (`item_packaging_type_id`),
  KEY `item_variants_owner_id_foreign` (`owner_id`),
  CONSTRAINT `item_variants_item_color_id_foreign` FOREIGN KEY (`item_color_id`) REFERENCES `item_colors` (`id`) ON DELETE CASCADE,
  CONSTRAINT `item_variants_item_id_foreign` FOREIGN KEY (`item_id`) REFERENCES `items` (`id`) ON DELETE CASCADE,
  CONSTRAINT `item_variants_item_packaging_type_id_foreign` FOREIGN KEY (`item_packaging_type_id`) REFERENCES `item_packaging_types` (`id`) ON DELETE CASCADE,
  CONSTRAINT `item_variants_item_size_id_foreign` FOREIGN KEY (`item_size_id`) REFERENCES `item_sizes` (`id`) ON DELETE CASCADE,
  CONSTRAINT `item_variants_owner_id_foreign` FOREIGN KEY (`owner_id`) REFERENCES `users` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=1630 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

